import React, { useState, useEffect } from 'react';

const LOGO_DATA_URI = 'data:image/jpeg;base64,';

const FONT_HEADING = "'Fredoka One', cursive";
const FONT_BODY = "'Nunito', sans-serif";

const MENU_STORAGE_KEY = 'menu_items';

const DEFAULT_MENU = [
  { id: 'chicken', name: 'Chicken Salad', price: 20000, desc: 'Chicken, red onion, cucumber, tomato, black pepper, oregano, mayonnaise, chilli (optional)', category: 'salad' },
  { id: 'beef', name: 'Beef Salad', price: 20000, desc: 'Beef, red onion, cucumber, tomato, lettuce, black pepper, mayonnaise, chilli (optional)', category: 'salad' },
  { id: 'eggmeat', name: 'Egg & Meat Salad', price: 25000, desc: 'Egg, meat of choice, red onion, cucumber, lettuce, black pepper, mayonnaise, chilli (optional)', category: 'salad' },
  { id: 'pasta', name: 'Pasta Salad', price: 25000, desc: 'Pasta, meat of choice, red onion, cucumber, spring onion, mayonnaise, chilli (optional)', category: 'salad' },
  { id: '5050', name: '50:50 Meat Salad', price: 35000, desc: 'Beef & chicken, cucumber & onion mix, mayo, black pepper, oregano', category: 'salad' },
  { id: 'tea_apple', name: 'Apple & Cinnamon Ice Tea', price: 12000, desc: 'Crisp apple warmth with a cinnamon finish — 400ml, chilled', category: 'tea' },
  { id: 'tea_mint', name: 'Sweet Peppermint Ice Tea', price: 12000, desc: 'Cool, refreshing peppermint with a gentle sweetness — 400ml, chilled', category: 'tea' },
  { id: 'tea_raspberry', name: 'Raspberry Leaf Ice Tea', price: 12000, desc: 'Delicate raspberry with a smooth herbal note — 400ml, chilled', category: 'tea' },
];

async function loadMenu() {
  try {
    const result = await window.storage.get(MENU_STORAGE_KEY, true);
    if (result?.value) {
      const parsed = JSON.parse(result.value);
      if (Array.isArray(parsed) && parsed.length > 0) return parsed;
    }
  } catch (e) { /* use defaults */ }
  return DEFAULT_MENU.map(item => ({ ...item }));
}

async function saveMenu(menu) {
  await window.storage.set(MENU_STORAGE_KEY, JSON.stringify(menu), true);
}

const PIN_STORAGE_KEY = 'admin_pin';
const DEFAULT_PIN = '1234';

async function loadPin() {
  try {
    const result = await window.storage.get(PIN_STORAGE_KEY, true);
    if (result?.value && String(result.value).trim()) {
      return String(result.value).trim();
    }
  } catch (e) { /* use default */ }
  return DEFAULT_PIN;
}

async function savePin(pin) {
  await window.storage.set(PIN_STORAGE_KEY, String(pin).trim(), true);
}

const ZONES = [
  { id: 'zone1', name: 'Zone 1 — Muyenga & Surroundings', fee: 3000, areas: 'Muyenga, Kisugu, Kiwafu, Bukasa, Kiwuliriza' },
  { id: 'zone2', name: 'Zone 2 — Near Neighbours', fee: 4000, areas: 'Kabalagala, Kansanga, Nsambya, Bunga, Buziga, Ggaba' },
  { id: 'zone3', name: 'Zone 3 — Mid Kampala', fee: 5000, areas: 'Makindye, Kibuli, Munyonyo, Luzira, Nakawa, Kibuye, Bugolobi, Naguru, Mbuya, Port Bell' },
  { id: 'zone4', name: 'Zone 4 — Far Kampala (still within the city)', fee: 7000, areas: 'Nakasero, Kololo, Kamwokya, Old Kampala, Mengo, Lubaga, Wandegeya, Makerere, Mulago, Katwe, Ndeeba, Nateete, Wakaliga, Busega, Namuwongo, Naakulabye, Namungoona, Lungujja, Kyanja, Kulambiro, Kisaasi, Kanyanya, Kyebando, Kawempe, Bukoto, Kalerwe, Kasubi' },
  { id: 'zone5', name: 'Zone 5 — Outside Kampala (Wakiso & Mukono districts)', fee: 10000, areas: 'Najjera, Namugongo, Mukono, Seeta, Wakiso, Kiwatule, Naalya, Kyaliwajjala, Bweyogere, Kireka, Nansana, Bulenga, Kyengera, Gayaza, Kasangati, Lubowa, Entebbe Road' },
];

// Flat list mapping each individual area name to its zone, used for the searchable area picker
const AREA_INDEX = ZONES.flatMap(zone =>
  zone.areas.split(',').map(a => a.trim()).map(areaName => ({
    areaName,
    zoneId: zone.id,
    zoneName: zone.name,
    fee: zone.fee,
  }))
);

const PAYMENT_METHODS = [
  { id: 'cash', label: 'Cash on Delivery', desc: 'Pay the rider when your order arrives' },
  { id: 'momo', label: 'Mobile Money', desc: 'Send to 0765119166' },
];

function fmt(n) {
  return n.toLocaleString('en-UG');
}

function Logo() {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
      <img
        src={LOGO_DATA_URI}
        alt="Salad Box logo"
        style={{ width: 56, height: 56, objectFit: 'contain', flexShrink: 0 }}
      />
      <div style={{ display: 'flex', alignItems: 'baseline', gap: 10, flexWrap: 'wrap' }}>
        <div style={{ fontFamily: FONT_HEADING, fontWeight: 400, fontSize: 22, color: '#1a1a1a', lineHeight: 1, letterSpacing: 0.5 }}>
          SALAD <span style={{ color: '#4e9d35' }}>BOX</span>
        </div>
        <div style={{ fontFamily: FONT_BODY, fontSize: 11, letterSpacing: 1.2, color: '#6b6b6b', textTransform: 'uppercase' }}>
          Muyenga, Kampala
        </div>
      </div>
    </div>
  );
}

function OrderForm({ onOrderPlaced, menu }) {
  const [cart, setCart] = useState({}); // saladId -> qty
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [zoneId, setZoneId] = useState('');
  const [areaSearch, setAreaSearch] = useState('');
  const [showAreaResults, setShowAreaResults] = useState(false);
  const [address, setAddress] = useState('');
  const [notes, setNotes] = useState('');
  const [deliveryDate, setDeliveryDate] = useState(''); // ISO date string YYYY-MM-DD
  const [paymentMethod, setPaymentMethod] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [confirmed, setConfirmed] = useState(null);
  const [error, setError] = useState('');
  const [fieldErrors, setFieldErrors] = useState({});
  const [showConfirmPopup, setShowConfirmPopup] = useState(false);

  // Build "Tomorrow" + next 6 days as quick-pick options
  const dateOptions = (() => {
    const opts = [];
    const today = new Date();
    for (let i = 1; i <= 7; i++) {
      const d = new Date(today);
      d.setDate(today.getDate() + i);
      const iso = d.toISOString().slice(0, 10);
      const label = i === 1
        ? 'Tomorrow — ' + d.toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short' })
        : d.toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short' });
      opts.push({ iso, label });
    }
    return opts;
  })();

  const updateQty = (id, delta) => {
    setCart(prev => {
      const next = { ...prev };
      const newQty = (next[id] || 0) + delta;
      if (newQty <= 0) delete next[id];
      else next[id] = newQty;
      return next;
    });
  };

  const itemsTotal = Object.entries(cart).reduce((sum, [id, qty]) => {
    const salad = menu.find(s => s.id === id);
    return sum + (salad ? salad.price * qty : 0);
  }, 0);

  const zone = ZONES.find(z => z.id === zoneId);
  const deliveryFee = zone ? zone.fee : 0;
  const grandTotal = itemsTotal + deliveryFee;
  const totalItems = Object.values(cart).reduce((a, b) => a + b, 0);

  const totalSaladItems = Object.entries(cart).reduce((sum, [id, qty]) => {
    const item = menu.find(s => s.id === id);
    return sum + (item && item.category === 'salad' ? qty : 0);
  }, 0);
  const canSubmit = totalSaladItems > 0 && name.trim() && phone.trim() && zoneId && address.trim() && deliveryDate && paymentMethod;

  const getMissingFields = () => {
    const missing = [];
    if (totalSaladItems <= 0) missing.push({ key: 'salad', label: 'at least one salad' });
    if (!name.trim()) missing.push({ key: 'name', label: 'full name' });
    if (!phone.trim()) missing.push({ key: 'phone', label: 'phone number' });
    if (!zoneId) missing.push({ key: 'zone', label: 'delivery area / zone' });
    if (!address.trim()) missing.push({ key: 'address', label: 'delivery address' });
    if (!deliveryDate) missing.push({ key: 'date', label: 'delivery date' });
    if (!paymentMethod) missing.push({ key: 'payment', label: 'payment method' });
    return missing;
  };

  const clearFieldError = (key) => {
    setFieldErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const attemptPlaceOrder = () => {
    const missing = getMissingFields();
    if (missing.length > 0) {
      const errors = {};
      missing.forEach(m => { errors[m.key] = true; });
      setFieldErrors(errors);
      const labels = missing.map(m => m.label);
      const list = labels.length === 1
        ? labels[0]
        : labels.slice(0, -1).join(', ') + ' and ' + labels[labels.length - 1];
      setError(`Please complete: ${list}.`);
      const first = document.getElementById('field-' + missing[0].key);
      if (first) first.scrollIntoView({ behavior: 'smooth', block: 'center' });
      return;
    }
    setFieldErrors({});
    setError('');
    setShowConfirmPopup(true);
  };

  const handleSubmit = async () => {
    setError('');
    const missing = getMissingFields();
    if (missing.length > 0) {
      attemptPlaceOrder();
      return;
    }
    setSubmitting(true);
    try {
      const order = {
        id: 'order_' + Date.now() + '_' + Math.random().toString(36).slice(2, 7),
        timestamp: new Date().toISOString(),
        deliveryDate,
        deliveryDateLabel: dateOptions.find(d => d.iso === deliveryDate)?.label || deliveryDate,
        paymentMethod,
        paymentMethodLabel: PAYMENT_METHODS.find(p => p.id === paymentMethod)?.label || paymentMethod,
        name: name.trim(),
        phone: phone.trim(),
        zoneId,
        zoneName: zone.name,
        deliveryFee,
        address: address.trim(),
        notes: notes.trim(),
        items: Object.entries(cart).map(([id, qty]) => {
          const s = menu.find(s => s.id === id);
          return { id, name: s.name, price: s.price, qty };
        }),
        itemsTotal,
        grandTotal,
        status: 'pending',
      };

      // Diagnostic: test a minimal write first to isolate any storage failure early
      try {
        await window.storage.set('diagnostic_test', 'hello', true);
      } catch (testErr) {
        throw new Error('STORAGE_UNAVAILABLE: ' + (testErr && testErr.message ? testErr.message : String(testErr)));
      }

      const saveResult = await window.storage.set(order.id, JSON.stringify(order), true);
      if (!saveResult) {
        throw new Error('STORAGE_SET_FAILED: set() returned null/falsy');
      }

      // update index list — read-modify-write with retry in case of race conditions
      let attempts = 0;
      let indexSaved = false;
      while (attempts < 3 && !indexSaved) {
        attempts++;
        let index = [];
        try {
          const indexReadResult = await window.storage.get('order_index', true);
          if (indexReadResult && indexReadResult.value) {
            index = JSON.parse(indexReadResult.value);
          }
        } catch (e) {
          index = []; // key doesn't exist yet — first order ever
        }
        if (!index.includes(order.id)) {
          index.push(order.id);
        }
        const indexWriteResult = await window.storage.set('order_index', JSON.stringify(index), true);
        if (indexWriteResult) {
          indexSaved = true;
        }
      }
      if (!indexSaved) {
        console.warn('Order saved but index update failed after retries:', order.id);
      }

      setConfirmed(order);
      setCart({});
      setName('');
      setPhone('');
      setZoneId('');
      setAreaSearch('');
      setAddress('');
      setNotes('');
      setDeliveryDate('');
      setPaymentMethod('');
      if (onOrderPlaced) onOrderPlaced();
    } catch (e) {
      console.error('Order submission error:', e);
      const rawMsg = (e && e.message) ? e.message : String(e);
      setError('Something went wrong placing your order. Please try again, or contact us directly if it keeps happening.');
    } finally {
      setSubmitting(false);
    }
  };

  if (confirmed) {
    return (
      <div style={{ textAlign: 'center', padding: '48px 24px' }}>
        <div style={{ fontSize: 48, marginBottom: 16 }}>✅</div>
        <h2 style={{ fontFamily: FONT_HEADING, fontSize: 26, color: '#1a1a1a', marginBottom: 8 }}>
          Order received, {confirmed.name.split(' ')[0]}!
        </h2>
        <p style={{ color: '#6b6b6b', fontSize: 14, marginBottom: 8 }}>
          Delivery scheduled for <strong style={{ color: '#1a1a1a' }}>{confirmed.deliveryDateLabel}</strong>
        </p>
        <p style={{ color: '#6b6b6b', fontSize: 14, marginBottom: 8 }}>
          Payment: <strong style={{ color: '#1a1a1a' }}>{confirmed.paymentMethodLabel}</strong>
          {confirmed.paymentMethod === 'momo' && (
            <span> — send to <strong style={{ color: '#4e9d35' }}>0765119166</strong></span>
          )}
        </p>
        <p style={{ color: '#6b6b6b', fontSize: 14, marginBottom: 24 }}>
          We'll call you on {confirmed.phone} to confirm delivery.
        </p>
        <div style={{
          background: '#fff', border: '1px solid #e0e0dc', borderRadius: 12,
          padding: 20, maxWidth: 360, margin: '0 auto', textAlign: 'left',
        }}>
          {confirmed.items.map(it => (
            <div key={it.id} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, marginBottom: 6, color: '#1a1a1a' }}>
              <span>{it.qty}x {it.name}</span>
              <span>{fmt(it.price * it.qty)}</span>
            </div>
          ))}
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, marginTop: 10, paddingTop: 10, borderTop: '1px solid #e0e0dc', color: '#6b6b6b' }}>
            <span>Items subtotal</span>
            <span>UGX {fmt(confirmed.itemsTotal ?? confirmed.items.reduce((s, it) => s + it.price * it.qty, 0))}</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, marginTop: 6, color: '#6b6b6b' }}>
            <span>Transport ({confirmed.zoneName.split('—')[0].trim()})</span>
            <span>UGX {fmt(confirmed.deliveryFee || 0)}</span>
          </div>
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 16, fontWeight: 700, marginTop: 10, paddingTop: 10, borderTop: '1.5px solid #4e9d35', color: '#1a1a1a' }}>
            <span>Total</span>
            <span>UGX {fmt(confirmed.grandTotal)}</span>
          </div>
        </div>
        <button
          onClick={() => setConfirmed(null)}
          style={{
            marginTop: 24, background: '#4e9d35', color: '#fff', border: 'none',
            padding: '12px 28px', borderRadius: 8, fontSize: 14, fontWeight: 600, cursor: 'pointer',
            fontFamily: FONT_BODY,
          }}
        >
          Place another order
        </button>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 520, margin: '0 auto', padding: '24px 20px 60px' }}>
      <div style={{ fontFamily: FONT_HEADING, fontSize: 20, color: '#4e9d35', fontWeight: 700, marginBottom: -6 }}>
        Pre Order with
      </div>
      <h2 style={{ fontFamily: FONT_HEADING, fontSize: 26, color: '#1a1a1a', marginBottom: 4 }}>
        SALAD BOX
      </h2>
      <p style={{ color: '#6b6b6b', fontSize: 13, marginBottom: 24 }}>
        Pick your salad, add your details, and we'll get cooking.
      </p>

      {/* Salad selection */}
      <div id="field-salad" style={{ marginBottom: 28 }}>
        <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: 2, textTransform: 'uppercase', color: fieldErrors.salad ? '#c0392b' : '#4e9d35', marginBottom: 12 }}>
          1. Choose your Salad
        </div>
        {fieldErrors.salad && (
          <div style={{ fontSize: 12, color: '#c0392b', marginBottom: 8 }}>Please add at least one salad.</div>
        )}
        {menu.filter(s => s.category === 'salad').map(s => {
          const qty = cart[s.id] || 0;
          return (
            <div key={s.id} style={{
              display: 'flex', justifyContent: 'space-between', alignItems: 'center',
              background: '#fff', border: fieldErrors.salad ? '1.5px solid #e07468' : '1px solid #e0e0dc', borderRadius: 10,
              padding: '12px 14px', marginBottom: 8,
            }}>
              <div style={{ flex: 1, marginRight: 12 }}>
                <div style={{ fontWeight: 600, fontSize: 14, color: '#1a1a1a' }}>{s.name}</div>
                <div style={{ fontSize: 11.5, color: '#6b6b6b', marginTop: 2, lineHeight: 1.4 }}>{s.desc}</div>
                <div style={{ fontSize: 13, color: '#4e9d35', fontWeight: 600, marginTop: 4 }}>UGX {fmt(s.price)}</div>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexShrink: 0 }}>
                <button
                  onClick={() => { updateQty(s.id, -1); clearFieldError('salad'); }}
                  disabled={qty === 0}
                  style={{
                    width: 28, height: 28, borderRadius: '50%', border: '1px solid #d4d4d4',
                    background: qty === 0 ? '#f5f5f5' : '#fff', color: '#1a1a1a',
                    fontSize: 16, cursor: qty === 0 ? 'default' : 'pointer', lineHeight: 1,
                  }}
                >−</button>
                <span style={{ minWidth: 18, textAlign: 'center', fontWeight: 600, fontSize: 14 }}>{qty}</span>
                <button
                  onClick={() => { updateQty(s.id, 1); clearFieldError('salad'); }}
                  style={{
                    width: 28, height: 28, borderRadius: '50%', border: 'none',
                    background: '#4e9d35', color: '#fff', fontSize: 16, cursor: 'pointer', lineHeight: 1,
                  }}
                >+</button>
              </div>
            </div>
          );
        })}
      </div>

      {/* Ice tea selection */}
      <div style={{ marginBottom: 28 }}>
        <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: 2, textTransform: 'uppercase', color: '#4e9d35', marginBottom: 4 }}>
          Add an Ice Tea 🧊
        </div>
        <p style={{ fontSize: 12, color: '#6b6b6b', marginBottom: 12 }}>400ml — freshly brewed and chilled</p>
        {menu.filter(s => s.category === 'tea').map(s => {
          const qty = cart[s.id] || 0;
          return (
            <div key={s.id} style={{
              display: 'flex', justifyContent: 'space-between', alignItems: 'center',
              background: '#f5fbf7', border: '1px solid #c8e6d0', borderRadius: 10,
              padding: '12px 14px', marginBottom: 8,
            }}>
              <div style={{ flex: 1, marginRight: 12 }}>
                <div style={{ fontWeight: 600, fontSize: 14, color: '#1a1a1a' }}>{s.name}</div>
                <div style={{ fontSize: 11.5, color: '#6b6b6b', marginTop: 2, lineHeight: 1.4 }}>{s.desc}</div>
                <div style={{ fontSize: 13, color: '#4e9d35', fontWeight: 600, marginTop: 4 }}>UGX {fmt(s.price)}</div>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexShrink: 0 }}>
                <button
                  onClick={() => updateQty(s.id, -1)}
                  disabled={qty === 0}
                  style={{
                    width: 28, height: 28, borderRadius: '50%', border: '1px solid #d4d4d4',
                    background: qty === 0 ? '#f5f5f5' : '#fff', color: '#1a1a1a',
                    fontSize: 16, cursor: qty === 0 ? 'default' : 'pointer', lineHeight: 1,
                  }}
                >−</button>
                <span style={{ minWidth: 18, textAlign: 'center', fontWeight: 600, fontSize: 14 }}>{qty}</span>
                <button
                  onClick={() => updateQty(s.id, 1)}
                  style={{
                    width: 28, height: 28, borderRadius: '50%', border: 'none',
                    background: '#4e9d35', color: '#fff', fontSize: 16, cursor: 'pointer', lineHeight: 1,
                  }}
                >+</button>
              </div>
            </div>
          );
        })}
      </div>

      {/* Customer details */}
      <div id="field-name" style={{ marginBottom: 28 }}>
        <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: 2, textTransform: 'uppercase', color: (fieldErrors.name || fieldErrors.phone) ? '#c0392b' : '#4e9d35', marginBottom: 12 }}>
          2. Your details
        </div>
        <input
          placeholder="Full name"
          value={name}
          onChange={e => { setName(e.target.value); clearFieldError('name'); }}
          style={{
            ...inputStyle,
            border: fieldErrors.name ? '1.5px solid #e07468' : inputStyle.border,
            background: fieldErrors.name ? '#fdf6f5' : inputStyle.background,
          }}
        />
        {fieldErrors.name && <div style={{ fontSize: 12, color: '#c0392b', marginTop: -4, marginBottom: 8 }}>Full name is required.</div>}
        <input
          id="field-phone"
          placeholder="Phone number (for delivery confirmation)"
          value={phone}
          onChange={e => { setPhone(e.target.value); clearFieldError('phone'); }}
          style={{
            ...inputStyle,
            border: fieldErrors.phone ? '1.5px solid #e07468' : inputStyle.border,
            background: fieldErrors.phone ? '#fdf6f5' : inputStyle.background,
          }}
        />
        {fieldErrors.phone && <div style={{ fontSize: 12, color: '#c0392b', marginTop: -4, marginBottom: 8 }}>Phone number is required.</div>}
      </div>

      {/* Delivery zone */}
      <div id="field-zone" style={{ marginBottom: 28 }}>
        <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: 2, textTransform: 'uppercase', color: (fieldErrors.zone || fieldErrors.address) ? '#c0392b' : '#4e9d35', marginBottom: 12 }}>
          3. Delivery zone
        </div>
        {fieldErrors.zone && (
          <div style={{ fontSize: 12, color: '#c0392b', marginBottom: 8 }}>Please select your delivery area.</div>
        )}

        <div style={{ position: 'relative', marginBottom: 8 }}>
          <input
            placeholder="Search your area e.g. Kyanja, Muyenga, Ntinda..."
            value={areaSearch}
            onChange={e => {
              setAreaSearch(e.target.value);
              setShowAreaResults(true);
              if (zoneId) setZoneId(''); // clear confirmed zone while user is editing search
              clearFieldError('zone');
            }}
            onFocus={() => setShowAreaResults(true)}
            style={{
              ...inputStyle,
              marginBottom: 0,
              border: fieldErrors.zone ? '1.5px solid #e07468' : inputStyle.border,
              background: fieldErrors.zone ? '#fdf6f5' : inputStyle.background,
            }}
          />

          {showAreaResults && areaSearch.trim().length > 0 && (
            <div style={{
              position: 'absolute', top: '100%', left: 0, right: 0, zIndex: 20,
              background: '#fff', border: '1px solid #e0e0dc', borderRadius: 10,
              marginTop: 4, maxHeight: 220, overflowY: 'auto',
              boxShadow: '0 4px 16px rgba(0,0,0,0.1)',
            }}>
              {(() => {
                const query = areaSearch.trim().toLowerCase();
                const matches = AREA_INDEX.filter(a => a.areaName.toLowerCase().startsWith(query));
                const fallbackMatches = matches.length > 0
                  ? matches
                  : AREA_INDEX.filter(a => a.areaName.toLowerCase().includes(query));

                if (fallbackMatches.length === 0) {
                  return (
                    <div style={{ padding: '14px', fontSize: 12.5, color: '#6b6b6b' }}>
                      No matching area found — you can still pick a zone manually below, or describe your location in the address field.
                    </div>
                  );
                }

                return fallbackMatches.slice(0, 8).map((a, i) => (
                  <button
                    key={a.areaName + i}
                    onClick={() => {
                      setZoneId(a.zoneId);
                      setAreaSearch(a.areaName);
                      setShowAreaResults(false);
                      clearFieldError('zone');
                    }}
                    style={{
                      width: '100%', textAlign: 'left', padding: '11px 14px', background: 'none',
                      border: 'none', borderBottom: i < fallbackMatches.length - 1 ? '1px solid #f0f0ec' : 'none',
                      cursor: 'pointer',
                    }}
                  >
                    <span style={{ fontSize: 13.5, color: '#1a1a1a', fontFamily: FONT_BODY }}>{a.areaName}</span>
                  </button>
                ));
              })()}
            </div>
          )}
        </div>

        {zone && (
          <div style={{
            display: 'flex', justifyContent: 'space-between', alignItems: 'center',
            background: '#eef6f0', border: '1.5px solid #4e9d35', borderRadius: 10,
            padding: '12px 14px', marginBottom: 8,
          }}>
            <div>
              <div style={{ fontWeight: 700, fontSize: 13.5, color: '#1a1a1a' }}>✓ {areaSearch || 'Area confirmed'}</div>
              <div style={{ fontSize: 11.5, color: '#6b6b6b', marginTop: 2 }}>We deliver here — fee added to your total below</div>
            </div>
          </div>
        )}

        <details style={{ marginBottom: 8 }}>
          <summary style={{ fontSize: 12, color: '#4e9d35', fontWeight: 700, cursor: 'pointer', padding: '4px 0' }}>
            Can't find your area? See all areas we deliver to
          </summary>
          <div style={{ marginTop: 8, maxHeight: 260, overflowY: 'auto', border: '1px solid #e0e0dc', borderRadius: 10, padding: '8px' }}>
            {AREA_INDEX.map((a, i) => (
              <button
                key={a.areaName + i}
                onClick={() => {
                  setZoneId(a.zoneId);
                  setAreaSearch(a.areaName);
                  setShowAreaResults(false);
                  clearFieldError('zone');
                }}
                style={{
                  width: '100%', textAlign: 'left', padding: '9px 10px',
                  background: (zoneId === a.zoneId && areaSearch === a.areaName) ? '#eef6f0' : 'none',
                  border: 'none', borderBottom: i < AREA_INDEX.length - 1 ? '1px solid #f0f0ec' : 'none',
                  cursor: 'pointer', fontSize: 13, color: '#1a1a1a', fontFamily: FONT_BODY,
                }}
              >
                {a.areaName}
              </button>
            ))}
          </div>
        </details>

        <input
          id="field-address"
          placeholder="Delivery address / landmark details"
          value={address}
          onChange={e => { setAddress(e.target.value); clearFieldError('address'); }}
          style={{
            ...inputStyle,
            border: fieldErrors.address ? '1.5px solid #e07468' : inputStyle.border,
            background: fieldErrors.address ? '#fdf6f5' : inputStyle.background,
          }}
        />
        {fieldErrors.address && <div style={{ fontSize: 12, color: '#c0392b', marginTop: -4, marginBottom: 8 }}>Delivery address is required.</div>}
        <textarea
          placeholder="Any notes for your order (optional)"
          value={notes}
          onChange={e => setNotes(e.target.value)}
          style={{ ...inputStyle, minHeight: 60, resize: 'vertical', fontFamily: 'inherit' }}
        />
      </div>

      {/* Delivery date */}
      <div id="field-date" style={{ marginBottom: 28 }}>
        <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: 2, textTransform: 'uppercase', color: fieldErrors.date ? '#c0392b' : '#4e9d35', marginBottom: 12 }}>
          4. Delivery date
        </div>
        {fieldErrors.date && (
          <div style={{ fontSize: 12, color: '#c0392b', marginBottom: 8 }}>Please choose a delivery date.</div>
        )}
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
          {dateOptions.map(d => (
            <button
              key={d.iso}
              onClick={() => { setDeliveryDate(d.iso); clearFieldError('date'); }}
              style={{
                padding: '9px 14px', borderRadius: 20, fontSize: 12.5, fontWeight: 600,
                border: deliveryDate === d.iso ? 'none' : fieldErrors.date ? '1.5px solid #e07468' : '1px solid #e0e0dc',
                background: deliveryDate === d.iso ? '#4e9d35' : '#fff',
                color: deliveryDate === d.iso ? '#fff' : '#1a1a1a',
                cursor: 'pointer',
              }}
            >
              {d.label}
            </button>
          ))}
        </div>
      </div>

      {/* Payment method */}
      <div id="field-payment" style={{ marginBottom: 28 }}>
        <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: 2, textTransform: 'uppercase', color: fieldErrors.payment ? '#c0392b' : '#4e9d35', marginBottom: 12 }}>
          5. Payment method
        </div>
        {fieldErrors.payment && (
          <div style={{ fontSize: 12, color: '#c0392b', marginBottom: 8 }}>Please select a payment method.</div>
        )}
        {PAYMENT_METHODS.map(p => (
          <label key={p.id} style={{
            display: 'flex', alignItems: 'flex-start', gap: 10,
            background: paymentMethod === p.id ? '#eef6f0' : '#fff',
            border: paymentMethod === p.id ? '1.5px solid #4e9d35' : fieldErrors.payment ? '1.5px solid #e07468' : '1px solid #e0e0dc',
            borderRadius: 10, padding: '12px 14px', marginBottom: 8, cursor: 'pointer',
          }}>
            <input
              type="radio"
              name="payment"
              value={p.id}
              checked={paymentMethod === p.id}
              onChange={() => { setPaymentMethod(p.id); clearFieldError('payment'); }}
              style={{ marginTop: 3 }}
            />
            <div style={{ flex: 1 }}>
              <div style={{ fontWeight: 600, fontSize: 13.5, color: '#1a1a1a' }}>{p.label}</div>
              <div style={{ fontSize: 11.5, color: '#6b6b6b', marginTop: 2 }}>{p.desc}</div>
            </div>
          </label>
        ))}
        {paymentMethod === 'momo' && (
          <div style={{
            background: '#fdf3e3', border: '1px solid #f0deb0', borderRadius: 10,
            padding: '12px 14px', fontSize: 12.5, color: '#8a6d1f', marginTop: 4,
          }}>
            📱 Send UGX {fmt(grandTotal)} to <strong>0765119166</strong> and keep your transaction message — the rider may ask to confirm it on delivery.
          </div>
        )}
      </div>

      {/* Summary */}
      <div style={{
        background: '#1a1a1a', borderRadius: 14, padding: '18px 20px', color: '#fff', marginBottom: 16,
      }}>
        {totalItems === 0 ? (
          <div style={{ fontSize: 13, color: 'rgba(255,255,255,0.6)', textAlign: 'center' }}>
            Add a salad to see your total
          </div>
        ) : (
          <>
            {Object.entries(cart).map(([id, qty]) => {
              const s = menu.find(s => s.id === id);
              return (
                <div key={id} style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, marginBottom: 5, color: 'rgba(255,255,255,0.85)' }}>
                  <span>{qty}x {s.name}</span>
                  <span>{fmt(s.price * qty)}</span>
                </div>
              );
            })}
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, marginBottom: 5, color: 'rgba(255,255,255,0.6)', paddingTop: 6, borderTop: '1px solid rgba(255,255,255,0.15)' }}>
              <span>Items subtotal</span>
              <span>{fmt(itemsTotal)}</span>
            </div>
            {zone && (
              <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, marginBottom: 5, color: 'rgba(255,255,255,0.6)' }}>
                <span>Transport</span>
                <span>{fmt(deliveryFee)}</span>
              </div>
            )}
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 18, fontWeight: 700, marginTop: 10, paddingTop: 10, borderTop: '1.5px solid rgba(255,255,255,0.25)' }}>
              <span>Total</span>
              <span style={{ color: '#4e9d35' }}>UGX {fmt(grandTotal)}</span>
            </div>
          </>
        )}
      </div>

      {error && (
        <div style={{
          color: '#c0392b', fontSize: 13, marginBottom: 12, textAlign: 'left',
          background: '#fdf0ee', border: '1px solid #f0c4bd', borderRadius: 10, padding: '12px 14px',
        }}>
          {error}
        </div>
      )}

      <button
        onClick={attemptPlaceOrder}
        disabled={submitting}
        style={{
          width: '100%', background: canSubmit ? '#4e9d35' : '#4e9d35', color: '#fff',
          border: 'none', padding: '14px', borderRadius: 10, fontSize: 15, fontWeight: 600,
          cursor: submitting ? 'default' : 'pointer', opacity: submitting ? 0.7 : 1,
        }}
      >
        {submitting ? 'Placing order...' : `Place order — UGX ${fmt(grandTotal)}`}
      </button>
      <p style={{ fontSize: 11, color: '#6b6b6b', textAlign: 'center', marginTop: 10 }}>
        By confirming, you agree to the total amount shown above, payable on delivery.
      </p>

      {showConfirmPopup && (
        <div style={{
          position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
          background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center',
          justifyContent: 'center', zIndex: 100, padding: 20,
        }}>
          <div style={{
            background: '#fff', borderRadius: 16, padding: '28px 24px',
            maxWidth: 340, width: '100%', textAlign: 'center',
          }}>
            <div style={{ fontSize: 36, marginBottom: 12 }}>🥗</div>
            <h3 style={{ fontFamily: FONT_HEADING, fontSize: 19, color: '#1a1a1a', marginBottom: 8 }}>
              Place this order?
            </h3>
            <p style={{ fontSize: 13, color: '#6b6b6b', marginBottom: 6, lineHeight: 1.5 }}>
              Total: <strong style={{ color: '#4e9d35' }}>UGX {fmt(grandTotal)}</strong>
            </p>
            <p style={{ fontSize: 12, color: '#6b6b6b', marginBottom: 22, lineHeight: 1.5 }}>
              Tapping Cancel will clear everything you've selected.
            </p>
            <div style={{ display: 'flex', gap: 10 }}>
              <button
                onClick={() => {
                  setShowConfirmPopup(false);
                  setCart({});
                  setName('');
                  setPhone('');
                  setZoneId('');
                  setAreaSearch('');
                  setAddress('');
                  setNotes('');
                  setDeliveryDate('');
                  setPaymentMethod('');
                }}
                style={{
                  flex: 1, background: 'none', color: '#c0392b', border: '1px solid #f0c4bd',
                  padding: '12px', borderRadius: 10, fontSize: 14, fontWeight: 600, cursor: 'pointer',
                }}
              >
                Cancel
              </button>
              <button
                onClick={() => {
                  setShowConfirmPopup(false);
                  handleSubmit();
                }}
                style={{
                  flex: 1, background: '#4e9d35', color: '#fff', border: 'none',
                  padding: '12px', borderRadius: 10, fontSize: 14, fontWeight: 700, cursor: 'pointer',
                }}
              >
                Confirm
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

const inputStyle = {
  width: '100%', padding: '11px 14px', borderRadius: 8, border: '1px solid #e0e0dc',
  fontSize: 13.5, marginBottom: 8, outline: 'none', color: '#1a1a1a', background: '#fff',
};

function Dashboard({ menu, onMenuChange, adminPin, onPinChange }) {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [dashTab, setDashTab] = useState('orders'); // 'orders' | 'menu'

  const loadOrders = async () => {
    setLoading(true);
    try {
      const indexResult = await window.storage.get('order_index', true);
      const index = indexResult ? JSON.parse(indexResult.value) : [];
      const loaded = [];
      for (const id of index) {
        try {
          const r = await window.storage.get(id, true);
          if (r) loaded.push(JSON.parse(r.value));
        } catch (e) { /* skip missing */ }
      }
      loaded.sort((a, b) => new Date(b.timestamp) - new Date(a.timestamp));
      setOrders(loaded);
    } catch (e) {
      setOrders([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { loadOrders(); }, []);

  const markStatus = async (order, status) => {
    const updated = { ...order, status };
    await window.storage.set(order.id, JSON.stringify(updated), true);
    setOrders(prev => prev.map(o => o.id === order.id ? updated : o));
  };

  // Unique delivery dates present in the orders, soonest first
  const deliveryDates = [...new Set(orders.map(o => o.deliveryDate).filter(Boolean))].sort();
  const defaultDate = deliveryDates[0] || '';
  const [selectedDate, setSelectedDate] = useState('');
  const activeDate = selectedDate || defaultDate;

  const ordersForDate = orders.filter(o => o.deliveryDate === activeDate);
  const filtered = ordersForDate.filter(o => filter === 'all' || o.status === filter);
  const orderItemsTotal = (o) =>
    o.itemsTotal ?? (o.items || []).reduce((sum, it) => sum + (it.price * it.qty), 0);
  const orderDeliveryFee = (o) => o.deliveryFee || 0;

  const dateRevenue = ordersForDate.filter(o => o.status !== 'cancelled').reduce((sum, o) => sum + o.grandTotal, 0);
  const dateItemsRevenue = ordersForDate.filter(o => o.status !== 'cancelled').reduce((sum, o) => sum + orderItemsTotal(o), 0);
  const dateTransportRevenue = ordersForDate.filter(o => o.status !== 'cancelled').reduce((sum, o) => sum + orderDeliveryFee(o), 0);

  const formatDateLabel = (iso) => {
    if (!iso) return '';
    const d = new Date(iso + 'T00:00:00');
    return d.toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'short' });
  };

  const handlePrint = () => {
    const printOrders = ordersForDate; // print all orders for the day, regardless of status filter
    const rows = printOrders.map((o, i) => `
      <tr style="${o.status === 'cancelled' ? 'opacity:0.5;text-decoration:line-through;' : ''}">
        <td style="padding:8px;border:1px solid #ddd;text-align:center;">${i + 1}</td>
        <td style="padding:8px;border:1px solid #ddd;">
          <strong>${o.name}</strong><br/>
          <span style="color:#666;font-size:12px;">${o.phone}</span>
        </td>
        <td style="padding:8px;border:1px solid #ddd;">
          ${o.items.map(it => `${it.qty}x ${it.name}`).join('<br/>')}
        </td>
        <td style="padding:8px;border:1px solid #ddd;font-size:12px;">
          ${o.zoneName.replace(/^Zone \d+\s*—\s*/, '')}<br/>
          ${o.address}
        </td>
        <td style="padding:8px;border:1px solid #ddd;font-size:12px;">
          ${o.paymentMethodLabel || '—'}
        </td>
        <td style="padding:8px;border:1px solid #ddd;text-align:right;font-size:12px;">
          ${fmt(orderItemsTotal(o))}<br/>
          <span style="color:#666;">+ ${fmt(orderDeliveryFee(o))} transport</span>
        </td>
        <td style="padding:8px;border:1px solid #ddd;text-align:right;">
          <strong>${fmt(o.grandTotal)}</strong>
        </td>
        <td style="padding:8px;border:1px solid #ddd;text-align:center;font-size:11px;">
          ${o.status === 'delivered' ? '✅ Delivered' : o.status === 'cancelled' ? '❌ Cancelled' : '⬜ Pending'}
        </td>
      </tr>
    `).join('');

    const totalRevenue = printOrders.filter(o => o.status !== 'cancelled').reduce((sum, o) => sum + o.grandTotal, 0);
    const cancelledCount = printOrders.filter(o => o.status === 'cancelled').length;

    const html = `
      <!DOCTYPE html>
      <html>
      <head>
        <meta charset="UTF-8">
        <title>Salad Box Orders — ${formatDateLabel(activeDate)}</title>
        <style>
          body { font-family: Arial, sans-serif; padding: 24px; color: #1a1a1a; }
          h1 { font-size: 20px; margin-bottom: 4px; }
          .sub { color: #666; font-size: 13px; margin-bottom: 20px; }
          table { width: 100%; border-collapse: collapse; margin-top: 12px; }
          th { background: #1a1a1a; color: #fff; padding: 8px; text-align: left; font-size: 12px; text-transform: uppercase; }
          .summary { margin-top: 20px; font-size: 14px; }
          .summary strong { color: #1a1a1a; }
          @media print {
            body { padding: 0; }
          }
        </style>
      </head>
      <body>
        <h1>🥗 Salad Box — Order Sheet</h1>
        <div class="sub">Delivery day: ${formatDateLabel(activeDate)} &nbsp;|&nbsp; Printed: ${new Date().toLocaleString('en-GB')}</div>
        <table>
          <thead>
            <tr>
              <th>#</th>
              <th>Customer</th>
              <th>Order</th>
              <th>Delivery</th>
              <th>Payment</th>
              <th style="text-align:right;">Items + Transport</th>
              <th style="text-align:right;">Total</th>
              <th>Done</th>
            </tr>
          </thead>
          <tbody>
            ${rows || '<tr><td colspan="8" style="padding:16px;text-align:center;color:#999;">No orders for this day</td></tr>'}
          </tbody>
        </table>
        <div class="summary">
          <strong>Total orders:</strong> ${printOrders.length}
          ${cancelledCount > 0 ? ` (${cancelledCount} cancelled)` : ''} &nbsp;|&nbsp;
          <strong>Items:</strong> UGX ${fmt(printOrders.filter(o => o.status !== 'cancelled').reduce((s, o) => s + orderItemsTotal(o), 0))} &nbsp;|&nbsp;
          <strong>Transport:</strong> UGX ${fmt(printOrders.filter(o => o.status !== 'cancelled').reduce((s, o) => s + orderDeliveryFee(o), 0))} &nbsp;|&nbsp;
          <strong>Total revenue:</strong> UGX ${fmt(totalRevenue)}
        </div>
      </body>
      </html>
    `;

    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(html);
      printWindow.document.close();
      printWindow.focus();
      setTimeout(() => printWindow.print(), 300);
    }
  };

  return (
    <div style={{ maxWidth: 640, margin: '0 auto', padding: '24px 20px 60px' }}>
      <div style={{ display: 'flex', gap: 4, background: '#f0f0ec', borderRadius: 20, padding: 3, marginBottom: 20, width: 'fit-content' }}>
        <button
          onClick={() => setDashTab('orders')}
          style={{
            padding: '7px 16px', borderRadius: 17, fontSize: 12, fontWeight: 800, border: 'none',
            fontFamily: FONT_BODY, cursor: 'pointer',
            background: dashTab === 'orders' ? '#4e9d35' : 'transparent',
            color: dashTab === 'orders' ? '#fff' : '#6b6b6b',
          }}
        >
          Orders
        </button>
        <button
          onClick={() => setDashTab('menu')}
          style={{
            padding: '7px 16px', borderRadius: 17, fontSize: 12, fontWeight: 800, border: 'none',
            fontFamily: FONT_BODY, cursor: 'pointer',
            background: dashTab === 'menu' ? '#4e9d35' : 'transparent',
            color: dashTab === 'menu' ? '#fff' : '#6b6b6b',
          }}
        >
          Menu
        </button>
        <button
          onClick={() => setDashTab('settings')}
          style={{
            padding: '7px 16px', borderRadius: 17, fontSize: 12, fontWeight: 800, border: 'none',
            fontFamily: FONT_BODY, cursor: 'pointer',
            background: dashTab === 'settings' ? '#4e9d35' : 'transparent',
            color: dashTab === 'settings' ? '#fff' : '#6b6b6b',
          }}
        >
          Settings
        </button>
      </div>

      {dashTab === 'menu' ? (
        <MenuEditor menu={menu} onMenuChange={onMenuChange} />
      ) : dashTab === 'settings' ? (
        <PinSettings currentPin={adminPin} onPinChange={onPinChange} />
      ) : (
      <>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'baseline', marginBottom: 18 }}>
        <h2 style={{ fontFamily: FONT_HEADING, fontSize: 24, color: '#1a1a1a' }}>Orders</h2>
        <div style={{ display: 'flex', gap: 14, alignItems: 'center' }}>
          <button onClick={handlePrint} style={{ fontSize: 12, color: '#4e9d35', background: 'none', border: 'none', cursor: 'pointer', fontWeight: 600 }}>
            🖨 Print Day
          </button>
          <button onClick={loadOrders} style={{ fontSize: 12, color: '#4e9d35', background: 'none', border: 'none', cursor: 'pointer', fontWeight: 600 }}>
            ↻ Refresh
          </button>
        </div>
      </div>

      {deliveryDates.length > 0 && (
        <div style={{ marginBottom: 16 }}>
          <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: 1.5, textTransform: 'uppercase', color: '#6b6b6b', marginBottom: 8 }}>
            Viewing delivery day
          </div>
          <div style={{ display: 'flex', gap: 8, overflowX: 'auto', paddingBottom: 4 }}>
            {deliveryDates.map(iso => (
              <button
                key={iso}
                onClick={() => setSelectedDate(iso)}
                style={{
                  padding: '8px 14px', borderRadius: 20, fontSize: 12.5, fontWeight: 600, whiteSpace: 'nowrap',
                  border: activeDate === iso ? 'none' : '1px solid #e0e0dc',
                  background: activeDate === iso ? '#4e9d35' : '#fff',
                  color: activeDate === iso ? '#fff' : '#1a1a1a',
                  cursor: 'pointer', flexShrink: 0,
                }}
              >
                {formatDateLabel(iso)}
              </button>
            ))}
          </div>
        </div>
      )}

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 10 }}>
        <div style={{ background: '#fff', border: '1px solid #e0e0dc', borderRadius: 10, padding: 14 }}>
          <div style={{ fontSize: 11, color: '#6b6b6b', textTransform: 'uppercase', letterSpacing: 1 }}>
            {activeDate ? formatDateLabel(activeDate) + ' Orders' : 'Orders'}
          </div>
          <div style={{ fontSize: 24, fontWeight: 700, color: '#1a1a1a', fontFamily: FONT_HEADING }}>{ordersForDate.length}</div>
        </div>
        <div style={{ background: '#fff', border: '1px solid #e0e0dc', borderRadius: 10, padding: 14 }}>
          <div style={{ fontSize: 11, color: '#6b6b6b', textTransform: 'uppercase', letterSpacing: 1 }}>Menu items</div>
          <div style={{ fontSize: 20, fontWeight: 700, color: '#1a1a1a', fontFamily: FONT_HEADING }}>{fmt(dateItemsRevenue)}</div>
        </div>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 20 }}>
        <div style={{ background: '#fff', border: '1.5px solid #4e9d35', borderRadius: 10, padding: 14 }}>
          <div style={{ fontSize: 11, color: '#4e9d35', textTransform: 'uppercase', letterSpacing: 1 }}>Total transport</div>
          <div style={{ fontSize: 20, fontWeight: 700, color: '#1a1a1a', fontFamily: FONT_HEADING }}>{fmt(dateTransportRevenue)}</div>
        </div>
        <div style={{ background: '#1a1a1a', borderRadius: 10, padding: 14 }}>
          <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.6)', textTransform: 'uppercase', letterSpacing: 1 }}>Total revenue</div>
          <div style={{ fontSize: 20, fontWeight: 700, color: '#4e9d35', fontFamily: FONT_HEADING }}>{fmt(dateRevenue)}</div>
        </div>
      </div>

      <div style={{ display: 'flex', gap: 8, marginBottom: 16 }}>
        {['all', 'pending', 'delivered', 'cancelled'].map(f => (
          <button
            key={f}
            onClick={() => setFilter(f)}
            style={{
              padding: '6px 14px', borderRadius: 20, fontSize: 12, fontWeight: 600,
              border: filter === f ? 'none' : '1px solid #e0e0dc',
              background: filter === f ? '#4e9d35' : '#fff',
              color: filter === f ? '#fff' : '#6b6b6b',
              cursor: 'pointer', textTransform: 'capitalize',
            }}
          >
            {f} {f !== 'all' && `(${ordersForDate.filter(o => o.status === f).length})`}
          </button>
        ))}
      </div>

      {loading ? (
        <div style={{ textAlign: 'center', color: '#6b6b6b', padding: 40, fontSize: 13 }}>Loading orders...</div>
      ) : deliveryDates.length === 0 ? (
        <div style={{ textAlign: 'center', color: '#6b6b6b', padding: 40, fontSize: 13 }}>
          No orders placed yet.
        </div>
      ) : filtered.length === 0 ? (
        <div style={{ textAlign: 'center', color: '#6b6b6b', padding: 40, fontSize: 13 }}>
          No {filter !== 'all' ? filter : ''} orders for {formatDateLabel(activeDate)}.
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
          {filtered.map(o => (
            <div key={o.id} style={{
              background: '#fff', border: '1px solid #e0e0dc', borderRadius: 12, padding: 16,
            }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 8 }}>
                <div>
                  <div style={{ fontWeight: 700, fontSize: 14.5, color: '#1a1a1a' }}>{o.name}</div>
                  <div style={{ fontSize: 12, color: '#6b6b6b' }}>{o.phone}</div>
                </div>
                <span style={{
                  fontSize: 10, fontWeight: 600, padding: '3px 10px', borderRadius: 20,
                  textTransform: 'uppercase', letterSpacing: 0.5,
                  background: o.status === 'pending' ? '#fdf3e3' : o.status === 'cancelled' ? '#fbe9e7' : '#e9f5ee',
                  color: o.status === 'pending' ? '#b8860b' : o.status === 'cancelled' ? '#c0392b' : '#4e9d35',
                }}>
                  {o.status}
                </span>
              </div>
              <div style={{ fontSize: 12.5, color: '#1a1a1a', marginBottom: 6, lineHeight: 1.6 }}>
                {o.items.map(it => `${it.qty}x ${it.name}`).join(', ')}
              </div>
              <div style={{ fontSize: 11.5, color: '#6b6b6b', marginBottom: 6 }}>
                📍 {o.zoneName} — {o.address}
              </div>
              <div style={{ fontSize: 11.5, color: '#6b6b6b', marginBottom: 6 }}>
                💳 {o.paymentMethodLabel || 'Not specified'}
              </div>
              {o.notes && (
                <div style={{ fontSize: 11.5, color: '#6b6b6b', marginBottom: 6, fontStyle: 'italic' }}>
                  Note: {o.notes}
                </div>
              )}
              <div style={{ marginTop: 10, paddingTop: 10, borderTop: '1px solid #f0f0ec' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12.5, color: '#6b6b6b', marginBottom: 4 }}>
                  <span>Menu items</span>
                  <span>UGX {fmt(orderItemsTotal(o))}</span>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12.5, color: '#6b6b6b', marginBottom: 6 }}>
                  <span>Transport</span>
                  <span>UGX {fmt(orderDeliveryFee(o))}</span>
                </div>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <div style={{ fontSize: 11, color: '#a8a8a8' }}>
                    {new Date(o.timestamp).toLocaleString('en-GB', { day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit' })}
                  </div>
                  <div style={{ fontSize: 15, fontWeight: 700, color: '#4e9d35' }}>Total UGX {fmt(o.grandTotal)}</div>
                </div>
              </div>
              {o.status === 'pending' && (
                <div style={{ display: 'flex', gap: 8, marginTop: 10 }}>
                  <button
                    onClick={() => markStatus(o, 'delivered')}
                    style={{
                      flex: 1, background: '#4e9d35', color: '#fff',
                      border: 'none', padding: '8px', borderRadius: 8, fontSize: 12.5, fontWeight: 600, cursor: 'pointer',
                    }}
                  >
                    Mark as delivered
                  </button>
                  <button
                    onClick={() => {
                      if (window.confirm(`Cancel ${o.name}'s order for UGX ${fmt(o.grandTotal)}?`)) {
                        markStatus(o, 'cancelled');
                      }
                    }}
                    style={{
                      flex: 1, background: 'none', color: '#c0392b',
                      border: '1px solid #f0c4bd', padding: '8px', borderRadius: 8, fontSize: 12.5, fontWeight: 600, cursor: 'pointer',
                    }}
                  >
                    Cancel order
                  </button>
                </div>
              )}
              {o.status === 'delivered' && (
                <button
                  onClick={() => markStatus(o, 'pending')}
                  style={{
                    width: '100%', marginTop: 10, background: 'none', color: '#6b6b6b',
                    border: '1px solid #e0e0dc', padding: '8px', borderRadius: 8, fontSize: 12.5, fontWeight: 600, cursor: 'pointer',
                  }}
                >
                  Move back to pending
                </button>
              )}
              {o.status === 'cancelled' && (
                <button
                  onClick={() => markStatus(o, 'pending')}
                  style={{
                    width: '100%', marginTop: 10, background: 'none', color: '#6b6b6b',
                    border: '1px solid #e0e0dc', padding: '8px', borderRadius: 8, fontSize: 12.5, fontWeight: 600, cursor: 'pointer',
                  }}
                >
                  Restore order
                </button>
              )}
            </div>
          ))}
        </div>
      )}
      </>
      )}
    </div>
  );
}

function MenuEditor({ menu, onMenuChange }) {
  const [items, setItems] = useState(menu);
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState('');
  const [editingId, setEditingId] = useState(null);
  const [draft, setDraft] = useState(null);
  const [adding, setAdding] = useState(false);
  const [newItem, setNewItem] = useState({ name: '', price: '', desc: '', category: 'salad' });

  useEffect(() => { setItems(menu); }, [menu]);

  const persist = async (next) => {
    setSaving(true);
    setMessage('');
    try {
      await saveMenu(next);
      setItems(next);
      onMenuChange(next);
      setMessage('Menu saved.');
    } catch (e) {
      setMessage('Could not save menu. Try again.');
    } finally {
      setSaving(false);
    }
  };

  const startEdit = (item) => {
    setEditingId(item.id);
    setDraft({ ...item, price: String(item.price) });
    setAdding(false);
  };

  const saveEdit = async () => {
    if (!draft.name.trim() || !draft.price) {
      setMessage('Name and price are required.');
      return;
    }
    const price = Number(String(draft.price).replace(/,/g, ''));
    if (!Number.isFinite(price) || price < 0) {
      setMessage('Enter a valid price.');
      return;
    }
    const next = items.map(it =>
      it.id === editingId
        ? { ...it, name: draft.name.trim(), price, desc: draft.desc.trim(), category: draft.category }
        : it
    );
    setEditingId(null);
    setDraft(null);
    await persist(next);
  };

  const removeItem = async (id) => {
    if (!window.confirm('Remove this menu item? Customers will no longer see it.')) return;
    await persist(items.filter(it => it.id !== id));
  };

  const addItem = async () => {
    if (!newItem.name.trim() || !newItem.price) {
      setMessage('Name and price are required.');
      return;
    }
    const price = Number(String(newItem.price).replace(/,/g, ''));
    if (!Number.isFinite(price) || price < 0) {
      setMessage('Enter a valid price.');
      return;
    }
    const id = 'item_' + Date.now() + '_' + Math.random().toString(36).slice(2, 6);
    const next = [...items, {
      id,
      name: newItem.name.trim(),
      price,
      desc: newItem.desc.trim(),
      category: newItem.category,
    }];
    setAdding(false);
    setNewItem({ name: '', price: '', desc: '', category: 'salad' });
    await persist(next);
  };

  const resetDefaults = async () => {
    if (!window.confirm('Reset menu to the original Salad Box items?')) return;
    await persist(DEFAULT_MENU.map(item => ({ ...item })));
  };

  const fieldStyle = { ...inputStyle, marginBottom: 8 };

  return (
    <div>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'baseline', marginBottom: 16 }}>
        <h2 style={{ fontFamily: FONT_HEADING, fontSize: 24, color: '#1a1a1a' }}>Menu</h2>
        <div style={{ display: 'flex', gap: 12 }}>
          <button
            onClick={() => { setAdding(true); setEditingId(null); setMessage(''); }}
            style={{ fontSize: 12, color: '#4e9d35', background: 'none', border: 'none', cursor: 'pointer', fontWeight: 600 }}
          >
            + Add item
          </button>
          <button
            onClick={resetDefaults}
            style={{ fontSize: 12, color: '#6b6b6b', background: 'none', border: 'none', cursor: 'pointer', fontWeight: 600 }}
          >
            Reset defaults
          </button>
        </div>
      </div>
      <p style={{ color: '#6b6b6b', fontSize: 13, marginBottom: 16 }}>
        Add, edit, or remove salads and ice teas. Changes show on the order form for customers.
      </p>
      {message && (
        <div style={{
          marginBottom: 12, padding: '10px 12px', borderRadius: 8, fontSize: 13,
          background: message.includes('Could') || message.includes('required') || message.includes('valid') ? '#fdf0ee' : '#eef8ea',
          color: message.includes('Could') || message.includes('required') || message.includes('valid') ? '#c0392b' : '#2d6a1f',
        }}>
          {message}
        </div>
      )}

      {adding && (
        <div style={{ background: '#fff', border: '1.5px solid #4e9d35', borderRadius: 12, padding: 14, marginBottom: 12 }}>
          <div style={{ fontWeight: 700, fontSize: 13, marginBottom: 10, color: '#1a1a1a' }}>New menu item</div>
          <input style={fieldStyle} placeholder="Name" value={newItem.name} onChange={e => setNewItem({ ...newItem, name: e.target.value })} />
          <input style={fieldStyle} placeholder="Price (UGX)" inputMode="numeric" value={newItem.price} onChange={e => setNewItem({ ...newItem, price: e.target.value })} />
          <textarea style={{ ...fieldStyle, minHeight: 64, resize: 'vertical' }} placeholder="Ingredients / description" value={newItem.desc} onChange={e => setNewItem({ ...newItem, desc: e.target.value })} />
          <select style={fieldStyle} value={newItem.category} onChange={e => setNewItem({ ...newItem, category: e.target.value })}>
            <option value="salad">Salad</option>
            <option value="tea">Ice Tea</option>
          </select>
          <div style={{ display: 'flex', gap: 8 }}>
            <button onClick={addItem} disabled={saving} style={{ flex: 1, background: '#4e9d35', color: '#fff', border: 'none', padding: '10px', borderRadius: 8, fontWeight: 700, cursor: 'pointer' }}>
              {saving ? 'Saving…' : 'Save item'}
            </button>
            <button onClick={() => setAdding(false)} style={{ flex: 1, background: 'none', border: '1px solid #e0e0dc', padding: '10px', borderRadius: 8, cursor: 'pointer' }}>
              Cancel
            </button>
          </div>
        </div>
      )}

      {items.map(item => (
        <div key={item.id} style={{
          background: '#fff', border: '1px solid #e0e0dc', borderRadius: 12, padding: 14, marginBottom: 10,
        }}>
          {editingId === item.id && draft ? (
            <>
              <input style={fieldStyle} value={draft.name} onChange={e => setDraft({ ...draft, name: e.target.value })} />
              <input style={fieldStyle} inputMode="numeric" value={draft.price} onChange={e => setDraft({ ...draft, price: e.target.value })} />
              <textarea style={{ ...fieldStyle, minHeight: 64, resize: 'vertical' }} value={draft.desc} onChange={e => setDraft({ ...draft, desc: e.target.value })} />
              <select style={fieldStyle} value={draft.category} onChange={e => setDraft({ ...draft, category: e.target.value })}>
                <option value="salad">Salad</option>
                <option value="tea">Ice Tea</option>
              </select>
              <div style={{ display: 'flex', gap: 8 }}>
                <button onClick={saveEdit} disabled={saving} style={{ flex: 1, background: '#4e9d35', color: '#fff', border: 'none', padding: '10px', borderRadius: 8, fontWeight: 700, cursor: 'pointer' }}>
                  {saving ? 'Saving…' : 'Save'}
                </button>
                <button onClick={() => { setEditingId(null); setDraft(null); }} style={{ flex: 1, background: 'none', border: '1px solid #e0e0dc', padding: '10px', borderRadius: 8, cursor: 'pointer' }}>
                  Cancel
                </button>
              </div>
            </>
          ) : (
            <>
              <div style={{ display: 'flex', justifyContent: 'space-between', gap: 12, alignItems: 'flex-start' }}>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 11, color: '#4e9d35', fontWeight: 700, textTransform: 'uppercase', letterSpacing: 1, marginBottom: 4 }}>
                    {item.category === 'tea' ? 'Ice Tea' : 'Salad'}
                  </div>
                  <div style={{ fontWeight: 700, fontSize: 14, color: '#1a1a1a' }}>{item.name}</div>
                  <div style={{ fontSize: 12, color: '#6b6b6b', marginTop: 4, lineHeight: 1.4 }}>{item.desc || 'No description'}</div>
                  <div style={{ fontSize: 13, color: '#4e9d35', fontWeight: 700, marginTop: 6 }}>UGX {fmt(item.price)}</div>
                </div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
                  <button onClick={() => startEdit(item)} style={{ fontSize: 12, color: '#4e9d35', background: 'none', border: '1px solid #c8e6d0', borderRadius: 8, padding: '6px 10px', cursor: 'pointer', fontWeight: 600 }}>
                    Edit
                  </button>
                  <button onClick={() => removeItem(item.id)} style={{ fontSize: 12, color: '#c0392b', background: 'none', border: '1px solid #f0c4bd', borderRadius: 8, padding: '6px 10px', cursor: 'pointer', fontWeight: 600 }}>
                    Remove
                  </button>
                </div>
              </div>
            </>
          )}
        </div>
      ))}
    </div>
  );
}

function PinSettings({ currentPin, onPinChange }) {
  const [current, setCurrent] = useState('');
  const [nextPin, setNextPin] = useState('');
  const [confirmPin, setConfirmPin] = useState('');
  const [message, setMessage] = useState('');
  const [saving, setSaving] = useState(false);

  const handleSave = async () => {
    setMessage('');
    if (current !== currentPin) {
      setMessage('Current PIN is incorrect.');
      return;
    }
    if (!/^\d{4,8}$/.test(nextPin)) {
      setMessage('New PIN must be 4–8 digits.');
      return;
    }
    if (nextPin !== confirmPin) {
      setMessage('New PIN and confirmation do not match.');
      return;
    }
    setSaving(true);
    try {
      await savePin(nextPin);
      onPinChange(nextPin);
      setCurrent('');
      setNextPin('');
      setConfirmPin('');
      setMessage('PIN updated successfully.');
    } catch (e) {
      setMessage('Could not save PIN. Try again.');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div>
      <h2 style={{ fontFamily: FONT_HEADING, fontSize: 24, color: '#1a1a1a', marginBottom: 8 }}>Settings</h2>
      <p style={{ color: '#6b6b6b', fontSize: 13, marginBottom: 20 }}>
        Change the staff PIN used to unlock the dashboard. Share the new PIN only with Salad Box staff.
      </p>
      <div style={{ background: '#fff', border: '1px solid #e0e0dc', borderRadius: 12, padding: 16, maxWidth: 400 }}>
        <div style={{ fontWeight: 700, fontSize: 14, marginBottom: 12, color: '#1a1a1a' }}>Change admin PIN</div>
        <input
          type="password"
          inputMode="numeric"
          placeholder="Current PIN"
          value={current}
          onChange={e => setCurrent(e.target.value)}
          style={{ ...inputStyle, letterSpacing: 3 }}
        />
        <input
          type="password"
          inputMode="numeric"
          placeholder="New PIN (4–8 digits)"
          value={nextPin}
          onChange={e => setNextPin(e.target.value)}
          style={{ ...inputStyle, letterSpacing: 3 }}
        />
        <input
          type="password"
          inputMode="numeric"
          placeholder="Confirm new PIN"
          value={confirmPin}
          onChange={e => setConfirmPin(e.target.value)}
          style={{ ...inputStyle, letterSpacing: 3 }}
        />
        {message && (
          <div style={{
            marginBottom: 12, padding: '10px 12px', borderRadius: 8, fontSize: 13,
            background: message.includes('success') ? '#eef8ea' : '#fdf0ee',
            color: message.includes('success') ? '#2d6a1f' : '#c0392b',
          }}>
            {message}
          </div>
        )}
        <button
          onClick={handleSave}
          disabled={saving}
          style={{
            width: '100%', background: '#4e9d35', color: '#fff', border: 'none',
            padding: '12px', borderRadius: 8, fontWeight: 700, cursor: 'pointer',
            fontFamily: FONT_BODY, opacity: saving ? 0.7 : 1,
          }}
        >
          {saving ? 'Saving…' : 'Update PIN'}
        </button>
      </div>
      <div style={{ marginTop: 20, fontSize: 12, color: '#6b6b6b', lineHeight: 1.5 }}>
        Staff login URL: add <code style={{ background: '#f0f0ec', padding: '2px 6px', borderRadius: 4 }}>?admin=1</code> to your site link.
        Default PIN before any change is <strong>1234</strong>.
      </div>
    </div>
  );
}

function PinGate({ onUnlock, expectedPin }) {
  const [pin, setPin] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = () => {
    if (pin === expectedPin) {
      setError('');
      onUnlock();
    } else {
      setError('Incorrect PIN. Please try again.');
      setPin('');
    }
  };

  return (
    <div style={{ maxWidth: 360, margin: '0 auto', padding: '80px 20px', textAlign: 'center' }}>
      <div style={{ fontSize: 40, marginBottom: 16 }}>🔒</div>
      <h2 style={{ fontFamily: FONT_HEADING, fontSize: 22, color: '#1a1a1a', marginBottom: 8 }}>
        Staff Access Only
      </h2>
      <p style={{ color: '#6b6b6b', fontSize: 13, marginBottom: 24 }}>
        Enter the PIN to view the orders dashboard.
      </p>
      <input
        type="password"
        inputMode="numeric"
        placeholder="Enter PIN"
        value={pin}
        onChange={e => setPin(e.target.value)}
        onKeyDown={e => { if (e.key === 'Enter') handleSubmit(); }}
        style={{
          width: '100%', padding: '14px', borderRadius: 10, border: '1.5px solid #e0e0dc',
          fontSize: 18, textAlign: 'center', letterSpacing: 4, marginBottom: 12, outline: 'none',
          fontFamily: FONT_BODY,
        }}
        autoFocus
      />
      {error && (
        <div style={{ color: '#c0392b', fontSize: 13, marginBottom: 12 }}>{error}</div>
      )}
      <button
        onClick={handleSubmit}
        style={{
          width: '100%', background: '#4e9d35', color: '#fff', border: 'none',
          padding: '13px', borderRadius: 10, fontSize: 14, fontWeight: 800, cursor: 'pointer',
          fontFamily: FONT_BODY,
        }}
      >
        Unlock Dashboard
      </button>
    </div>
  );
}

function isAdminMode() {
  if (typeof window === 'undefined') return false;
  const params = new URLSearchParams(window.location.search);
  return params.get('admin') === '1';
}

export default function App() {
  const [view, setView] = useState('order');
  const [dashboardUnlocked, setDashboardUnlocked] = useState(false);
  const [menu, setMenu] = useState(DEFAULT_MENU);
  const [adminPin, setAdminPin] = useState(DEFAULT_PIN);
  const [ready, setReady] = useState(false);
  const showAdmin = isAdminMode();

  useEffect(() => {
    let cancelled = false;
    (async () => {
      const [loadedMenu, loadedPin] = await Promise.all([loadMenu(), loadPin()]);
      if (!cancelled) {
        setMenu(loadedMenu);
        setAdminPin(loadedPin);
        setReady(true);
      }
    })();
    return () => { cancelled = true; };
  }, []);

  return (
    <div style={{ minHeight: '100vh', background: '#fafaf8', fontFamily: FONT_BODY }}>
      <div style={{
        background: '#fff', borderBottom: '2px solid #4e9d35', padding: '14px 20px',
        display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, zIndex: 10,
      }}>
        <Logo />
        {showAdmin && (
          <div style={{ display: 'flex', gap: 4, background: '#f0f0ec', borderRadius: 20, padding: 3 }}>
            <button
              onClick={() => setView('order')}
              style={{
                padding: '6px 14px', borderRadius: 17, fontSize: 12, fontWeight: 800, border: 'none',
                fontFamily: FONT_BODY,
                background: view === 'order' ? '#4e9d35' : 'transparent',
                color: view === 'order' ? '#fff' : '#6b6b6b',
                cursor: 'pointer', boxShadow: view === 'order' ? '0 1px 3px rgba(0,0,0,0.15)' : 'none',
              }}
            >
              Order
            </button>
            <button
              onClick={() => setView('dashboard')}
              style={{
                padding: '6px 14px', borderRadius: 17, fontSize: 12, fontWeight: 800, border: 'none',
                fontFamily: FONT_BODY,
                background: view === 'dashboard' ? '#4e9d35' : 'transparent',
                color: view === 'dashboard' ? '#fff' : '#6b6b6b',
                cursor: 'pointer', boxShadow: view === 'dashboard' ? '0 1px 3px rgba(0,0,0,0.15)' : 'none',
              }}
            >
              {dashboardUnlocked ? 'Dashboard' : '🔒 Dashboard'}
            </button>
          </div>
        )}
      </div>

      {!ready ? (
        <div style={{ textAlign: 'center', padding: 48, color: '#6b6b6b', fontSize: 14 }}>Loading…</div>
      ) : showAdmin && view === 'dashboard' ? (
        dashboardUnlocked ? (
          <Dashboard menu={menu} onMenuChange={setMenu} adminPin={adminPin} onPinChange={setAdminPin} />
        ) : (
          <PinGate expectedPin={adminPin} onUnlock={() => setDashboardUnlocked(true)} />
        )
      ) : (
        <OrderForm onOrderPlaced={() => {}} menu={menu} />
      )}
    </div>
  );
}